import { type DependencyList, useState } from 'react';
import { type DepsChangedEqualityFn, useDepsChanged } from '#registry/default/hooks/use-deps-changed.ts';

const increment = (v: number) => v + 1;

export function useDepsVersion<T extends DependencyList>(
  deps: T,
  equalityFn: DepsChangedEqualityFn<T[number]> = Object.is
): number {
  const [version, setVersion] = useState(0);
  const changed = useDepsChanged(deps, equalityFn);
  if (changed) setVersion(increment);
  return version;
}
